    private func authenticateWithBiometrics() {
        let biometricManager = BiometricAuthManager.shared
        let biometricType = biometricManager.getBiometricTypeName()
        
        biometricManager.authenticateWithBiometrics(reason: "Authenticate to access your account") { [weak self] success, error in
            guard let self = self else { return }
            
            if success {
                self.handleSuccessfulAuthentication()
            } else {
                if let error = error as? LAError {
                    self.handleBiometricError(error, biometricType: biometricType)
                }
            }
        }
    }
    
    private func handleBiometricError(_ error: LAError, biometricType: String) {
        var message = ""
        var showRetryOption = true
        
        switch error.code {
        case .authenticationFailed:
            message = "\(biometricType) authentication failed. Please try again or use your password."
        case .userCancel:
            message = "Authentication was cancelled."
            showRetryOption = false
        case .userFallback:
            return
        case .biometryNotAvailable:
            message = "\(biometricType) is not available on this device."
            showRetryOption = false
        case .biometryNotEnrolled:
            message = "\(biometricType) is not set up. Please set it up in Settings."
            showRetryOption = false
        case .biometryLockout:
            message = "\(biometricType) is locked due to too many failed attempts. Please use your password or try again later."
            showRetryOption = false
        case .passcodeNotSet:
            message = "Passcode is not set on this device."
            showRetryOption = false
        default:
            message = "Authentication failed. Please try again or use your password."
        }
        
        if showRetryOption {
            showRetryAlert(title: "Authentication Failed", message: message)
        } else {
            showAlert(title: "Authentication Failed", message: message)
        }
    }
    
